group-actions.ts 패턴 그대로 적용:
- 파일 상단: 'use server'
- createClient() from @/lib/supabase/server
- 에러 반환: { error: string }
- 성공 반환: { success: true } 또는 데이터
- revalidatePath + redirect 패턴

pseudocode:
```
async function updateRsvp(eventId, newStatus) {
  const event = await supabase.from('events').select('max_participants, group_id').eq('id', eventId).single()
  const existing = await supabase.from('event_participants').select('status').eq('event_id', eventId).eq('user_id', user.id).single()

  let finalStatus = newStatus
  let waitlistPosition = null

  if (newStatus === 'attending' && event.max_participants) {
    const attendingCount = await supabase.from('event_participants').select('id', {count: 'exact'}).eq('event_id', eventId).eq('status', 'attending')
    if (attendingCount >= event.max_participants) {
      finalStatus = 'waitlisted'
      const maxPosition = await supabase.from('event_participants').select('waitlist_position').eq('event_id', eventId).eq('status', 'waitlisted').order('waitlist_position', {ascending: false}).limit(1)
      waitlistPosition = (maxPosition?.[0]?.waitlist_position ?? 0) + 1
    }
  }

  if (existing?.status === 'attending' && newStatus !== 'attending') {
    await promoteWaitlisted(eventId)
  }

  await supabase.from('event_participants').upsert({ event_id: eventId, user_id: user.id, status: finalStatus, waitlist_position: waitlistPosition }, { onConflict: 'event_id,user_id' })
  revalidatePath(...)
}
```

